import type { RequestHandler } from "@builder.io/qwik-city";
import type { RateLimitResult } from "~/lib/rate-limiter";

/**
 * The `onRequest` middleware defined in `src/routes/api/layout.tsx` has
 * already enforced the rate limit (and set the `X-RateLimit-*` headers)
 * before this handler runs. Blocked requests never reach this file.
 */
function buildBody(method: "GET" | "POST", rateLimit: RateLimitResult | undefined) {
  return {
    method,
    message: `Hello from /api/data (${method})`,
    remaining: rateLimit?.remaining ?? 0,
    limit: rateLimit?.limit ?? 0,
  };
}

export const onGet: RequestHandler = async (requestEvent) => {
  const rateLimit = requestEvent.sharedMap.get("rateLimit") as RateLimitResult | undefined;
  requestEvent.json(200, buildBody("GET", rateLimit));
};

export const onPost: RequestHandler = async (requestEvent) => {
  const rateLimit = requestEvent.sharedMap.get("rateLimit") as RateLimitResult | undefined;
  requestEvent.json(200, buildBody("POST", rateLimit));
};

import { component$ } from "@builder.io/qwik";
import { routeLoader$ } from "@builder.io/qwik-city";
import { peek, getClientIp } from "~/lib/rate-limiter";

/**
 * Read-only lookup of the current rate-limit quota for the requesting
 * client IP. This uses `peek()`, which never increments the counters, so
 * viewing this page does not consume any of the client's quota.
 */
export const useRateLimitStatus = routeLoader$((requestEvent) => {
  const ip = getClientIp(requestEvent.request, requestEvent.clientConn.ip);
  const result = peek(ip);
  return { ip, ...result };
});

export default component$(() => {
  const status = useRateLimitStatus();

  return (
    <>
      <h1>Rate Limit Status</h1>
      <p>Limit: {status.value.limit}</p>
      <p>Remaining: {status.value.remaining}</p>
      <p>Reset: {status.value.resetSeconds}s</p>
    </>
  );
});
